<template>
  <v-container>
    <v-sheet>
      <!-- class markdown-body  -->
      <div class="markdown-body">
        <component :is="apps"></component>
      </div>
    </v-sheet>
  </v-container>
</template>
<script>
export default {
  name: "A",
  data() {
    return {
      Child: this.comChilds,
      apps: {},
    };
  },
  props: {
    comChilds: {
      type: String,
    },
  },
  beforeMount() {
    this.apps = () => import("../blog/" + this.Child + ".md");
  },
};
</script>